const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
if (!secret || secret !== (process.env.INTERNAL_EMAIL_SECRET || '')) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.policy_review_id) return { json: { _empty: true, error: 'policy_review_id required' } };
return { json: { _authorized: true, policy_review_id: body.policy_review_id } };

const rows = $input.item.json;
const r = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!r || !r.id) return { json: { _not_found: true, error: 'policy_review not found' } };
const esc = function (s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); };
const html = [
  '<!doctype html><html><head><meta charset="utf-8"><title>Policy Review Record</title>',
  '<style>body{font-family:Inter,sans-serif;max-width:720px;margin:32px auto;padding:0 24px;color:#1a1a1a;line-height:1.5}h1{color:#5B21B6}h2{color:#5B21B6;margin-top:24px;font-size:16px}.meta{color:#666;font-size:13px}pre{background:#F8F7FB;padding:12px 18px;border-radius:6px;font-size:13px;overflow-x:auto}</style>',
  '</head><body>',
  '<h1>Insurance Policy Review Record</h1>',
  '<p class="meta">Vertical: insurance · Review type: <strong>' + esc(r.review_type) + '</strong> · Conducted: ' + esc(r.conducted_date || '(pending)') + ' via ' + esc(r.conducted_via || '(unspecified)') + '</p>',
  '<h2>Trigger</h2><p>Source: ' + esc(r.trigger_source || 'scheduled') + '. Signal type: ' + esc(r.trigger_signal_type || '—') + '</p>',
  '<h2>Client situation changes</h2><pre>' + esc(JSON.stringify(r.client_situation_changes || {}, null, 2)) + '</pre>',
  '<h2>Coverage adequacy</h2><p><strong>' + (r.coverage_still_adequate === true ? 'YES — coverage remains adequate' : (r.coverage_still_adequate === false ? 'NO — adjustment recommended' : 'Pending')) + '</strong></p>',
  '<h2>Recommendations</h2><pre>' + esc(JSON.stringify(r.recommendations || [], null, 2)) + '</pre>',
  '<h2>Outcome</h2><p>' + esc(r.outcome || '(pending)') + '</p>',
  '<p class="meta" style="margin-top:40px">Generated by Crystallux AI · FSRA regulatory record · Compliance reference: REVIEW-' + esc(r.id) + '</p>',
  '</body></html>'
].join('\n');
const storageKey = 'reviews/insurance/' + (r.client_id || 'orphan') + '/' + r.id + '.html';
return { json: { html: html, storage_key: storageKey, review: r } };
